import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    dir_abs = os.path.abspath(dir_path)
    full_path = os.path.join(dir_abs, filename)
    if not full_path.startswith(dir_abs):
        return ""
    try:
        with open(full_path, 'r') as f:
            return f.read()
    except:
        return ""

